import { useState, useEffect, useRef } from "react";
const LOGO = `data:image/png;base64,`;

// ── Learning store ──────────────────────────────────────────────────────────
const STORE = "morgan_v3";
const getStore = () => { try { return JSON.parse(localStorage.getItem(STORE)||"{}"); } catch { return {}; } };
const saveStore = d => { try { localStorage.setItem(STORE, JSON.stringify(d)); } catch {} };
const learn = (type, topic, audience) => {
  const s = getStore();
  s.history = [{type,topic,audience,ts:Date.now()},...(s.history||[]).slice(0,49)];
  s.uses = (s.uses||0)+1;
  saveStore(s);
};
const getCtx = () => {
  const s = getStore();
  if(!s.history?.length) return "";
  return "Recent: "+s.history.slice(0,3).map(h=>h.topic+" for "+h.audience).join("; ");
};

